  excerpt: string;
  transcriptConfidence?: "high" | "medium" | "low";
  audioUrl?: string;
  linkedMemoryIds: string[];
};

type QueryRequest = {
  patientId: string;
  question: string;
  context?: "overview" | "passport" | "risk" | "handover";
};

type QueryAnswer = {
  id: string;
  question: string;
